var val = Services.getValue(TotalAssessedCost.dataBinding);
var err = validateCurrencyValue(val, 999999.99);
if( null == err)
{	Services.setValue( TotalAssessedCost.dataBinding, WPU.formatToTwoDP(val));
}
return err;

