function DefaultCurrency320() {}
DefaultCurrency320.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency320.tabIndex = -1;
DefaultCurrency320.maxLength = 1;
DefaultCurrency320.isReadOnly = function(){return true;}
DefaultCurrency320.isTemporary = function(){return true;}
DefaultCurrency320.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency320.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
